// TwistCalibrate.tsx
import React, {useState, useRef} from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {Canvas, Circle} from '@shopify/react-native-skia';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import {runOnJS} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
export function TwistCalibrate({onComplete}: {onComplete: () => void}) {
  const [dots, setDots] = useState<{x: number; y: number}[]>([]);
  const sweep = useRef(0); const lastAngle = useRef<number | null>(null);
  const add = (x: number, y: number) => setDots(d => [...d.slice(-30), {x, y}]);
  const pan = Gesture.Pan().onUpdate(e => { runOnJS(add)(e.x, e.y); const cx = 150; const cy = 150; const angle = Math.atan2(e.y - cy, e.x - cx); if (lastAngle.current !== null) { let delta = angle - lastAngle.current; if (delta > Math.PI) delta -= 2 * Math.PI; if (delta < -Math.PI) delta += 2 * Math.PI; sweep.current += Math.abs(delta); if (sweep.current > Math.PI * 4) { sweep.current = 0; runOnJS(Haptics.notificationAsync)(Haptics.NotificationFeedbackType.Success); runOnJS(onComplete)(); }} lastAngle.current = angle; }).onEnd(() => { lastAngle.current = null; sweep.current = 0; });
  return (<GestureDetector gesture={pan}><View style={{width:300, height:300}}><Canvas style={StyleSheet.absoluteFill}>{dots.map((d, i) => <Circle key={i} cx={d.x} cy={d.y} r={6} color='rgba(10,132,255,0.6)' opacity={(i + 1) / dots.length}/>)}</Canvas><Text style={s.hint}>Trace a figure-8</Text></View></GestureDetector>);
}
const s = StyleSheet.create({hint:{position:'absolute', top:8, alignSelf:'center', color:'#8E8E93'}});

