import React, {useMemo} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia, LinearGradient, vec} from '@shopify/react-native-skia';
export function AreaChart({points, width, height = 160, color = '#0A84FF'}: {points: number[]; width: number; height?: number; color?: string}) {
  const {linePath, areaPath} = useMemo(() => { const minV = Math.min(...points); const maxV = Math.max(...points); const range = maxV - minV || 1; const line = Skia.Path.Make(); const area = Skia.Path.Make(); points.forEach((v, i) => { const x = (i / (points.length - 1)) * width; const y = height - ((v - minV) / range) * (height - 10) - 5; if (i === 0) { line.moveTo(x, y); area.moveTo(x, height); area.lineTo(x, y); } else { line.lineTo(x, y); area.lineTo(x, y); }}); area.lineTo(width, height); area.close(); return {linePath: line, areaPath: area}; }, [points, width, height]);
  return (<View style={{width, height}}><Canvas style={StyleSheet.absoluteFill}><Path path={areaPath}><LinearGradient start={vec(0, 0)} end={vec(0, height)} colors={[color + '88', color + '00']}/></Path><Path path={linePath} style='stroke' strokeWidth={2} color={color}/></Canvas></View>);
}

