import React from 'react';
import {StyleSheet, View, Text} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withRepeat, withSequence, withTiming} from 'react-native-reanimated';
export function GlitchText({text}: {text: string}) {
  const x = useSharedValue(0);
  React.useEffect(() => { x.value = withRepeat(withSequence(withTiming(2, {duration: 60}), withTiming(-2, {duration: 60}), withTiming(0, {duration: 60}), withTiming(0, {duration: 2000})), -1, false); }, []);
  const magStyle = useAnimatedStyle(() => ({transform: [{translateX: x.value}]}));
  const cyStyle = useAnimatedStyle(() => ({transform: [{translateX: -x.value}]}));
  return (<View><Animated.Text style={[s.mag, magStyle]}>{text}</Animated.Text><Animated.Text style={[s.cy, cyStyle, {position: 'absolute'}]}>{text}</Animated.Text><Text style={s.white}>{text}</Text></View>);
}
